const chartArea = document.createElement('div');
chartArea.style.cssText = 'display: flex; align-items: end; justify-content: center; height: 120px;';

data.forEach((value, index) => {
    const barContainer = document.createElement('div');
    barContainer.style.cssText = 'display: flex; flex-direction: column; align-items: center; margin: 0 3px;';

    const bar = document.createElement('div');
    const height = (value / maxValue) * 80;
    bar.style.cssText = \`
        width: 25px;
        height: \${height}px;
        background: linear-gradient(to top, #007bff, #66b3ff);
        border-radius: 2px 2px 0 0;
        transition: all 0.3s ease;
    \`;

    const label = document.createElement('div');
    label.textContent = value.toString();
    label.style.cssText = 'font-size: 10px; margin-top: 5px; color: #666;';

    barContainer.appendChild(bar);
    barContainer.appendChild(label);
    chartArea.appendChild(barContainer);
});

chartContainer.appendChild(chartArea);
document.body.appendChild(chartContainer);
console.log('Interactive chart created with data:', data);`
    },
    'interactive-form': {
        name: 'Interactive Form',
        description: 'Form with validation and dynamic feedback',
        code: `// Interactive Contact Form
const formContainer = document.createElement('div');
formContainer.style.cssText = 'padding: 10px; font-family: Arial; background: white;';

formContainer.innerHTML = \`
    <h4 style="margin: 0 0 15px 0; color: #333;">Quick Contact</h4>
    <form id="contactForm">
        <div style="margin-bottom: 10px;">
